def levenshtein(a: String, b: String) -> Int:
    var n = len(a)
    var m = len(b)
    var prev = Array[Int](m + 1)
    for j in range(m + 1):
        prev[j] = j
    for i in range(1, n + 1):
        curr = Array[Int]()
        for j in range(m + 1):
            cost = 0 if a[i - 1] == b[j - 1] else 1
            var d = prev[j] + 1
            var ins = curr[j - 1] + 1
            var sub = prev[j - 1] + cost
            var mn = d
            if ins < mn:
                mn = ins
            if sub < mn:
                mn = sub
            curr.append(mn)
        prev = curr^
        if j == m:
            return prev[m]

